// Script Continued Below
var Organization_uiAction = Class.create();
Organization_uiAction.prototype = {
    initialize: function() {
    },

	// STRY0134695, STRY0130626
	canDeleteOOO: function(user_sys_id){
		// same as canCreate.  Call that until delete rules change
		var canDeleteOOO = this.canCreateOOO(user_sys_id);
		return canDeleteOOO;
	},

	// STRY0134695, STRY0130626
	canEditOOO: function(user_sys_id){
		// same as canCreate.  Call that until delete rules change
		var canEditOOO = this.canCreateOOO(user_sys_id);
		return canEditOOO;
	},

	// STRY0130940 
	canCreateOOO: function(user_sys_id){
		var answer = false;
		var currentUser_sys_id = gs.getUserID();

		var isCurrentUser = currentUser_sys_id == user_sys_id;
		var isTaskerApplicationAdministrator = gs.getUser().hasRole(
				tasking_System_Settings_Scripts.CONST_ROLE_TASKER_APPLICATION_ADMINISTRATOR);

		var isTaskAdministrator = gs.getUser().hasRole(
				tasking_System_Settings_Scripts.CONST_ROLE_TASK_ADMINISTRATOR);
		// DFCT0011638
		var isTaskManager = 
			new UserInfoScripts().IsUserOUTAOfAnotherUser(user_sys_id,currentUser_sys_id);

		if(isCurrentUser || isTaskAdministrator || isTaskManager || isTaskerApplicationAdministrator){
			answer=true;
		}
		return answer;
	},

	uiAction_createOoO: function(ooo) {
		try{
			ooo.insert();
			return true;
		}catch(e){
			gs.error(e);
			return false;
		}
	},
	// STRY0135127 
	uiAction_updateOoO: function(ooo) {
		try{
			ooo.update();
			return true;
		}catch(e){
			gs.error(e);
			return false;
		}
	},

	uiAction_deleteOoO: function(ooo) {
		ooo.deleteRecord();
	},

	uiAction_ActivateOU: function(ou) {
		ou.active = true;
		ou.update();
	},

	uiAction_DeactivateOU: function(ou) {
		ou.active = false;
		ou.update();		
	},

	uiAction_SaveOU: function(ou) {
		ou.insert();
	},

	uiAction_DeleteMember: function(member) {
		member.deleteRecord();
	},

	uiAction_SaveMember: function(member) {
		member.insert();
	},

	uiAction_SaveContactInfo: function(contact) {
		contact.insert();
	},

    type: 'Organization_uiAction'
};
